// ═══════════════════════════════════════════════════════════════════════════════
// PROTECAO.JS - Sistema de Proteção com Autenticação via postMessage
// Versão: 2.0 - Compatível com iframe (acordeão) e acesso direto
// ═══════════════════════════════════════════════════════════════════════════════

(function() {
    'use strict';
    
    // ═══════════════════════════════════════════════════════════════════════════
    // CONFIGURAÇÕES
    // ═══════════════════════════════════════════════════════════════════════════
    const CONFIG = {
        // Origens confiáveis (adicione seu domínio exato aqui)
        TRUSTED_ORIGINS: [
            'https://www.betstat.site',
            'https://betstat.site',
            'http://localhost',           // para desenvolvimento local
            'null'                        // para file:// ou iframe sandbox
        ],
        
        // Tempo máximo para aguardar autorização do parent (ms)
        AUTH_TIMEOUT: 2500,
        
        // Prefixo do token (deve bater com o do acordeão)
        TOKEN_PREFIX: 'betstat2024_secure_token_',
        
        // Parâmetro de bypass manual (emergência)
        BYPASS_PARAM: 'internal_access',
        
        // Se true, aplica proteções mínimas mesmo sem auth (modo desenvolvimento)
        DEV_MODE: false
    };
    
    // ═══════════════════════════════════════════════════════════════════════════
    // ESTADO GLOBAL
    // ═══════════════════════════════════════════════════════════════════════════
    const state = {
        isIframe: false,
        isAuthorized: false,
        authReceived: false,
        isDevToolsOpen: false,
        protectionLevel: 'full' // 'none' | 'minimal' | 'full'
    };
    
    // ═══════════════════════════════════════════════════════════════════════════
    // FUNÇÕES UTILITÁRIAS
    // ═══════════════════════════════════════════════════════════════════════════
    
    // Detecta se está rodando dentro de iframe
    function detectIframe() {
        try {
            return window.self !== window.top;
        } catch (e) {
            return true; // Cross-origin = provavelmente iframe
        }
    }
    
    // Verifica parâmetro de bypass na URL
    function checkBypassParam() {
        try {
            const params = new URLSearchParams(window.location.search);
            return params.get('bypass') === CONFIG.BYPASS_PARAM;
        } catch(e) {
            return false;
        }
    }
    
    // Verifica se consegue acessar parent (mesma origem)
    function isSameOrigin() {
        try {
            return window.parent.location.hostname === window.location.hostname;
        } catch(e) {
            return false;
        }
    }
    
    // Verifica se origem é confiável
    function isTrustedOrigin(origin) {
        if (!origin || origin === 'null') return true; // Permissive para iframes locais
        return CONFIG.TRUSTED_ORIGINS.some(trusted => 
            origin === trusted || origin.includes(trusted.replace('https://', '').replace('http://', ''))
        );
    }
    
    // ═══════════════════════════════════════════════════════════════════════════
    // SISTEMA DE AUTENTICAÇÃO VIA POSTMESSAGE
    // ═══════════════════════════════════════════════════════════════════════════
    
    function initAuthSystem() {
        return new Promise((resolve) => {
            state.isIframe = detectIframe();
            
            // Se não está em iframe e não tem bypass, é acesso direto
            if (!state.isIframe && !checkBypassParam()) {
                console.log('[Proteção] Acesso DIRETO detectado - proteções completas');
                state.protectionLevel = 'full';
                resolve(false);
                return;
            }
            
            // Se tem bypass, autoriza imediatamente
            if (checkBypassParam()) {
                console.log('[Proteção] Bypass manual ativado');
                state.isAuthorized = true;
                state.protectionLevel = 'minimal';
                resolve(true);
                return;
            }
            
            // Aguarda mensagem de autorização do parent
            const authTimeout = setTimeout(() => {
                if (!state.authReceived) {
                    // Timeout - verifica se é mesmo origem (desenvolvimento)
                    if (isSameOrigin()) {
                        console.log('[Proteção] Mesma origem detectada - autorizando');
                        state.isAuthorized = true;
                        state.protectionLevel = 'minimal';
                        resolve(true);
                    } else {
                        console.log('[Proteção] Timeout de auth - mantendo proteções');
                        state.protectionLevel = 'full';
                        resolve(false);
                    }
                }
            }, CONFIG.AUTH_TIMEOUT);
            
            // Listener para mensagens do parent
            window.addEventListener('message', function handler(e) {
                // Valida origem
                if (!isTrustedOrigin(e.origin)) {
                    return;
                }
                
                // Processa autorização
                if (e.data && e.data.action === 'authorizedLoad') {
                    // Valida token (formato: betstat2024_secure_token_YYYY-MM-DD)
                    const token = e.data.token || '';
                    const today = new Date().toISOString().split('T')[0];
                    const expectedToken = CONFIG.TOKEN_PREFIX + today;
                    
                    // Aceita token exato ou com data de hoje
                    if (token === expectedToken || token.startsWith(CONFIG.TOKEN_PREFIX)) {
                        clearTimeout(authTimeout);
                        state.authReceived = true;
                        state.isAuthorized = true;
                        state.protectionLevel = 'minimal';
                        
                        console.log('[Proteção] Autorizado via postMessage');
                        
                        // Confirma recebimento
                        if (e.source) {
                            try {
                                e.source.postMessage({
                                    action: 'authConfirmed',
                                    timestamp: Date.now(),
                                    url: window.location.href
                                }, '*');
                            } catch(err) {}
                        }
                        
                        window.removeEventListener('message', handler);
                        resolve(true);
                    }
                }
            });
        });
    }
    
    // ═══════════════════════════════════════════════════════════════════════════
    // PROTEÇÕES MÍNIMAS (para iframe autorizado)
    // ═══════════════════════════════════════════════════════════════════════════
    
    function applyMinimalProtection() {
        console.log('[Proteção] Aplicando proteções MÍNIMAS');
        
        // 1. Oculta header se existir (solicitação específica)
        const hideHeader = () => {
            const header = document.getElementById('header');
            if (header) {
                header.style.cssText = 'display:none !important; visibility:hidden !important; height:0 !important; overflow:hidden !important;';
                console.log('[Proteção] Header ocultado');
                return true;
            }
            return false;
        };
        
        // Tenta ocultar imediatamente e várias vezes após load
        if (!hideHeader()) {
            const attempts = [0, 100, 300, 500, 1000, 2000];
            attempts.forEach(delay => setTimeout(hideHeader, delay));
        }
        
        // Observa mudanças no DOM para ocultar header se aparecer depois
        if (window.MutationObserver) {
            const observer = new MutationObserver((mutations) => {
                const header = document.getElementById('header');
                if (header && header.style.display !== 'none') {
                    hideHeader();
                }
            });
            
            observer.observe(document.body || document.documentElement, {
                childList: true,
                subtree: true
            });
            
            // Para de observar após 5 segundos
            setTimeout(() => observer.disconnect(), 5000);
        }
        
        // 2. Proteção leve de teclado (opcional - descomente se quiser)
        /*
        document.addEventListener('keydown', function(e) {
            // Permite F12 mas bloqueia Ctrl+Shift+I/J apenas
            if (e.ctrlKey && e.shiftKey && (e.key === 'I' || e.key === 'J')) {
                // e.preventDefault(); // Descomente para bloquear
            }
        });
        */
        
        // 3. Notifica parent que está pronto
        if (window.parent && window.parent !== window) {
            const notifyReady = () => {
                try {
                    window.parent.postMessage({
                        action: 'toolReady',
                        url: window.location.href,
                        timestamp: Date.now()
                    }, '*');
                } catch(e) {}
            };
            
            notifyReady();
            setTimeout(notifyReady, 1000); // Garante que foi recebido
        }
    }
    
    // ═══════════════════════════════════════════════════════════════════════════
    // PROTEÇÕES COMPLETAS (para acesso direto não autorizado)
    // ═══════════════════════════════════════════════════════════════════════════
    
    function applyFullProtection() {
        console.log('[Proteção] Aplicando proteções COMPLETAS');
        
        // 1. Bloqueia menu de contexto (clique direito)
        document.addEventListener('contextmenu', function(e) {
            e.preventDefault();
            return false;
        }, true);
        
        // 2. Bloqueia atalhos de desenvolvimento
        document.addEventListener('keydown', function(e) {
            const key = e.key || e.keyCode;
            
            // F12
            if (key === 'F12' || key === 123) {
                e.preventDefault();
                return false;
            }
            
            // Ctrl + Shift + I (Inspecionar)
            if (e.ctrlKey && e.shiftKey && (key === 'I' || key === 73)) {
                e.preventDefault();
                return false;
            }
            
            // Ctrl + Shift + J (Console)
            if (e.ctrlKey && e.shiftKey && (key === 'J' || key === 74)) {
                e.preventDefault();
                return false;
            }
            
            // Ctrl + Shift + C (Inspeção de elemento)
            if (e.ctrlKey && e.shiftKey && (key === 'C' || key === 67)) {
                e.preventDefault();
                return false;
            }
            
            // Ctrl + U (Ver código fonte)
            if (e.ctrlKey && (key === 'u' || key === 'U' || key === 85)) {
                e.preventDefault();
                return false;
            }
            
            // Ctrl + S (Salvar)
            if (e.ctrlKey && (key === 's' || key === 'S' || key === 83)) {
                e.preventDefault();
                return false;
            }
            
            // Ctrl + P (Imprimir)
            if (e.ctrlKey && (key === 'p' || key === 'P' || key === 80)) {
                e.preventDefault();
                return false;
            }
        }, true);
        
        // 3. Detecta DevTools via debugger trap
        const devtoolsDetector = new Image();
        Object.defineProperty(devtoolsDetector, 'id', {
            get: function() {
                state.isDevToolsOpen = true;
                throw new Error('DevTools detectado');
            }
        });
        
        // 4. Detecta DevTools via dimensões da janela
        const threshold = 160;
        function checkDevTools() {
            const widthDiff = window.outerWidth - window.innerWidth;
            const heightDiff = window.outerHeight - window.innerHeight;
            
            if (widthDiff > threshold || heightDiff > threshold) {
                state.isDevToolsOpen = true;
            }
        }
        
        window.addEventListener('resize', checkDevTools);
        setInterval(checkDevTools, 500);
        
        // 5. Monitoramento contínuo
        console.log('%c', devtoolsDetector);
        
        setInterval(function() {
            if (state.isDevToolsOpen) {
                document.body.innerHTML = `
                    <div style="
                        position:fixed; top:0; left:0; width:100%; height:100%; 
                        background:#000; color:#fff; display:flex; 
                        align-items:center; justify-content:center; z-index:999999;
                        font-family:Arial,sans-serif; text-align:center;
                    ">
                        <div>
                            <h1 style="color:#ff4444; margin-bottom:20px;">⚠️ Acesso não autorizado detectado</h1>
                            <p>Ferramentas de desenvolvimento não são permitidas.</p>
                        </div>
                    </div>
                `;
                state.isDevToolsOpen = false;
                
                // Tenta notificar servidor (opcional)
                try {
                    fetch('/api/log-devtools', { method: 'POST', body: JSON.stringify({
                        url: window.location.href,
                        time: new Date().toISOString()
                    })}).catch(()=>{});
                } catch(e) {}
            }
        }, 1000);
        
        // 6. Impede seleção de texto
        document.addEventListener('selectstart', function(e) {
            e.preventDefault();
            return false;
        }, true);
        
        // 7. Impede drag and drop
        document.addEventListener('dragstart', function(e) {
            e.preventDefault();
            return false;
        }, true);
        
        // 8. Ofusca console
        const noop = function() {};
        const methods = ['log', 'debug', 'info', 'warn', 'error', 'table', 'clear', 'dir', 'trace'];
        methods.forEach(method => {
            console[method] = noop;
        });
        
        // 9. Proteção contra view-source:
        if (window.location.protocol === 'http:' || window.location.protocol === 'https:') {
            const currentUrl = window.location.href;
            if (currentUrl.includes('view-source:')) {
                window.location.href = currentUrl.replace('view-source:', '');
            }
        }
    }
    
    // ═══════════════════════════════════════════════════════════════════════════
    // INICIALIZAÇÃO
    // ═══════════════════════════════════════════════════════════════════════════
    
    async function init() {
        console.log('[Proteção] Inicializando...');
        
        // Aguarda autenticação
        const isAuthorized = await initAuthSystem();
        
        // Aplica proteções conforme o nível determinado
        if (state.protectionLevel === 'minimal' || (isAuthorized && state.isIframe)) {
            applyMinimalProtection();
        } else {
            applyFullProtection();
        }
        
        // Expõe estado para debug (remover em produção se desejar)
        window.BETSTAT_PROTECTION = {
            state: state,
            config: CONFIG,
            reapply: () => {
                if (state.protectionLevel === 'minimal') applyMinimalProtection();
                else applyFullProtection();
            }
        };
    }
    
    // Inicia quando DOM estiver pronto
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
    
})();